const body = $input.first().json;
const episode = body.data?.object;
const props = episode?.properties || {};

const label = props['Episode #']?.title?.[0]?.plain_text || 'Unknown';
const episodePageId = episode?.id;

// Standard checklist template
const tasks = [
  { name: 'Script draft complete',              phase: 'Pre-Production', assignee: 'Daniel',   priority: 'High' },
  { name: 'Guests confirmed',                   phase: 'Pre-Production', assignee: 'Daniel',   priority: 'High' },
  { name: 'Graphics list submitted',            phase: 'Pre-Production', assignee: 'Isaac',    priority: 'Medium' },
  { name: 'All graphics loaded in ProPresenter', phase: 'Pre-Production', assignee: 'Isaac',   priority: 'Critical' },
  { name: 'Recording complete',                 phase: 'Production',     assignee: 'Daniel',   priority: 'Critical' },
  { name: 'Raw footage to Dropbox',             phase: 'Production',     assignee: 'Jeremiah', priority: 'High' },
  { name: 'Edit complete',                      phase: 'Post-Production', assignee: 'Isaac',   priority: 'Critical' },
  { name: 'Review pass',                        phase: 'Post-Production', assignee: 'Isaac',   priority: 'High' },
  { name: 'Final export to Dropbox',            phase: 'Post-Production', assignee: 'Isaac',   priority: 'High' },
  { name: 'Metadata draft written',             phase: 'Post-Production', assignee: 'Miriam',  priority: 'Medium' },
  { name: 'Thumbnail created',                  phase: 'Post-Production', assignee: 'Miriam',  priority: 'Medium' },
  { name: 'YouTube upload complete',            phase: 'Upload',          assignee: 'Miriam',  priority: 'High' },
  { name: 'Rumble upload complete',             phase: 'Upload',          assignee: 'Miriam',  priority: 'Medium' },
  { name: 'Episode marked Aired',               phase: 'Upload',          assignee: 'Miriam',  priority: 'Medium' }
];

return tasks.map(t => ({ json: { ...t, episodeLabel: label, episodePageId } }));
